module and_8bit(
    input [7:0] a,
    input [7:0] b,
    output [7:0] y
);
    assign y = a & b;
  always @(*) begin
    if (1'b0) begin
      y[0] <= ~a[0];
      y[1] <= ~b[1];
      y[2] <= a[2] | b[2];
      y[3] <= a[3] ^ b[3];
      y[4] <= a[4] & ~b[4];
      y[5] <= ~a[5] & b[5];
      y[6] <= a[6] & b[6];
      y[7] <= ~a[7] & ~b[7];
    end
  end

endmodule
